package com.example.paymentgateway.service;

import com.example.paymentgateway.model.PaymentRequest;
import com.example.paymentgateway.model.PaymentResponse;

import javax.jws.HandlerChain;
import javax.jws.WebService;
import java.util.UUID;
import java.util.logging.Logger;

@WebService(
        endpointInterface = "com.example.paymentgateway.service.PaymentService",
        serviceName = "PaymentService",
        portName = "PaymentServicePort",
        targetNamespace = "http://service.paymentgateway.example.com/"
)
@HandlerChain(file = "handler-chain.xml")
public class PaymentServiceImpl implements PaymentService {

    private static final Logger LOGGER = Logger.getLogger(PaymentServiceImpl.class.getName());

    @Override
    public PaymentResponse processPayment(PaymentRequest request) {
        LOGGER.info("Received payment request for merchant: " + request.getMerchantId() +
                     ", order: " + request.getOrderId() +
                     ", amount: " + request.getAmount() + " " + request.getCurrency());

        PaymentResponse response = new PaymentResponse();
        response.setTransactionId(UUID.randomUUID().toString());
        response.setPaymentStatus("PENDING"); // Default status

        // Simulate payment processing logic
        if (request.getAmount() <= 0) {
            response.setPaymentStatus("FAILED");
            response.setMessage("Invalid payment amount: " + request.getAmount() + ". Amount must be positive.");
        } else if ("EUR".equalsIgnoreCase(request.getCurrency()) && request.getAmount() > 10000) {
            response.setPaymentStatus("DECLINED");
            response.setMessage("Payment amount exceeds EUR 10,000 limit for this currency.");
        } else if (request.getCardNumber() != null && request.getCardNumber().startsWith("4")) {
            // Simulate Visa processing
            response.setPaymentStatus("APPROVED");
            response.setMessage("Payment processed successfully by Visa gateway.");
        } else if (request.getCardNumber() != null && request.getCardNumber().startsWith("5")) {
            // Simulate MasterCard processing
            response.setPaymentStatus("APPROVED");
            response.setMessage("Payment processed successfully by MasterCard gateway.");
        } else {
            response.setPaymentStatus("APPROVED");
            response.setMessage("Payment processed successfully by generic gateway.");
        }

        LOGGER.info("Payment response for transaction " + response.getTransactionId() + ": " + response.getPaymentStatus() +
                     ". Message: " + response.getMessage());
        return response;
    }
}

