package com.example.paymentgateway.handler;

import javax.xml.namespace.QName;
import javax.xml.soap.SOAPBody;
import javax.xml.soap.SOAPConstants;
import javax.xml.soap.SOAPElement;
import javax.xml.soap.SOAPFactory;
import javax.xml.soap.SOAPFault;
import javax.xml.soap.SOAPHeader;
import javax.xml.soap.SOAPMessage;
import javax.xml.ws.handler.MessageContext;
import javax.xml.ws.handler.soap.SOAPHandler;
import javax.xml.ws.handler.soap.SOAPMessageContext;
import javax.xml.ws.soap.SOAPFaultException;
import org.w3c.dom.NodeList;

import java.time.Instant;
import java.time.format.DateTimeParseException;
import java.util.Collections;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;

public class TimestampSecurityHandler implements SOAPHandler<SOAPMessageContext> {

    private static final Logger LOGGER = Logger.getLogger(TimestampSecurityHandler.class.getName());

    // WS-Security and WS-Utility namespaces
    private static final String WSSE_NAMESPACE_URI = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NAMESPACE_URI = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String WSSE_PREFIX = "wsse";
    private static final String WSU_PREFIX = "wsu";

    // Cache for replay protection. Maps a unique identifier (e.g., wsu:Id) to its expiry timestamp (Epoch Millis).
    // For a production system, consider a dedicated caching solution (e.g., Guava Cache, Caffeine)
    // with automatic eviction and persistence if necessary.
    private static final ConcurrentHashMap<String, Long> REPLAY_CACHE = new ConcurrentHashMap<>();

    // Maximum allowed clock skew between client and server (e.g., 5 minutes)
    private static final long MAX_CLOCK_SKEW_MS = 5 * 60 * 1000;

    @Override
    public Set<QName> getHeaders() {
        // Indicate that this handler is interested in the WS-Security header.
        return Collections.singleton(new QName(WSSE_NAMESPACE_URI, "Security", WSSE_PREFIX));
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (!outbound) { // Processing an inbound message
            try {
                SOAPMessage soapMessage = context.getMessage();
                SOAPHeader header = soapMessage.getSOAPHeader();

                if (header == null) {
                    throw createSOAPFaultException("SOAP Header is missing. WS-Security requirements not met.", SOAPConstants.SOAP_SENDER_FAULT);
                }

                NodeList securityHeaders = header.getElementsByTagNameNS(WSSE_NAMESPACE_URI, "Security");

                if (securityHeaders.getLength() == 0) {
                    LOGGER.warning("WS-Security header is missing. Rejecting message.");
                    throw createSOAPFaultException("WS-Security 'Security' header is missing, which is required.", SOAPConstants.SOAP_SENDER_FAULT);
                }

                // Assuming only one Security header for simplicity.
                SOAPElement securityElement = (SOAPElement) securityHeaders.item(0);
                NodeList timestampElements = securityElement.getElementsByTagNameNS(WSU_NAMESPACE_URI, "Timestamp");

                if (timestampElements.getLength() == 0) {
                    LOGGER.warning("WS-Security 'Timestamp' element is missing. Rejecting message.");
                    throw createSOAPFaultException("WS-Security 'Timestamp' element is missing within the 'Security' header.", SOAPConstants.SOAP_SENDER_FAULT);
                }

                // Assuming only one Timestamp element
                SOAPElement timestampElement = (SOAPElement) timestampElements.item(0);
                String createdStr = getChildElementText(timestampElement, WSU_NAMESPACE_URI, "Created");
                String expiresStr = getChildElementText(timestampElement, WSU_NAMESPACE_URI, "Expires");
                String id = timestampElement.getAttributeNS(WSU_NAMESPACE_URI, "Id"); // wsu:Id attribute

                if (createdStr == null || expiresStr == null) {
                    LOGGER.warning("Timestamp 'Created' or 'Expires' element is missing. Rejecting message.");
                    throw createSOAPFaultException("Timestamp 'Created' or 'Expires' element is missing.", SOAPConstants.SOAP_SENDER_FAULT);
                }

                // Parse timestamps
                Instant created, expires;
                try {
                    created = Instant.parse(createdStr);
                    expires = Instant.parse(expiresStr);
                } catch (DateTimeParseException e) {
                    LOGGER.warning("Invalid timestamp format: " + e.getMessage());
                    throw createSOAPFaultException("Invalid timestamp format. Must be ISO 8601 UTC ('YYYY-MM-DDTHH:MM:SSZ').", SOAPConstants.SOAP_SENDER_FAULT);
                }

                Instant now = Instant.now();

                // 1. Check validity period (adjusted for clock skew)
                if (now.isBefore(created.minusMillis(MAX_CLOCK_SKEW_MS))) {
                    LOGGER.warning("Timestamp 'Created' is in the future. Created: " + created + ", Now: " + now);
                    throw createSOAPFaultException("Timestamp 'Created' is in the future. Adjusted for clock skew, it's not yet valid.", SOAPConstants.SOAP_SENDER_FAULT);
                }
                if (now.isAfter(expires.plusMillis(MAX_CLOCK_SKEW_MS))) {
                    LOGGER.warning("Timestamp 'Expires' has passed. Expires: " + expires + ", Now: " + now);
                    throw createSOAPFaultException("Timestamp 'Expires' has passed. Adjusted for clock skew, it's no longer valid.", SOAPConstants.SOAP_SENDER_FAULT);
                }

                // 2. Replay Protection
                // Use wsu:Id as the primary key for replay protection if available and expected to be unique.
                // Fallback to Created+Expires if Id is not present, though this is less robust for uniqueness.
                String timestampKey = (id != null && !id.isEmpty()) ? id : createdStr + "_" + expiresStr;

                Long existingExpiry = REPLAY_CACHE.get(timestampKey);
                if (existingExpiry != null) {
                    if (now.toEpochMilli() < existingExpiry) {
                        // This timestamp ID/combination has been seen before and is still within its validity period
                        LOGGER.warning("Replay attack detected for timestamp ID: " + timestampKey);
                        throw createSOAPFaultException("Replay attack detected: This message's timestamp has already been processed and is still valid.", SOAPConstants.SOAP_SENDER_FAULT);
                    } else {
                        // The existing entry has expired; it's not a replay of a currently valid timestamp.
                        // Remove it to allow a new message with the same (expired) ID, though typically IDs should be unique.
                        // A more robust replay cache would handle this with a dedicated cleanup thread.
                        REPLAY_CACHE.remove(timestampKey, existingExpiry);
                        LOGGER.info("Expired timestamp ID " + timestampKey + " found in cache and removed.");
                    }
                }

                // Add the current timestamp to the cache with its expiry.
                REPLAY_CACHE.put(timestampKey, expires.toEpochMilli());
                LOGGER.info("Timestamp ID " + timestampKey + " added to replay cache. Expires at: " + expires);

                // Optional: Store parsed timestamps in message context for downstream service access
                context.put("wssecurity.timestamp.created", created);
                context.setScope("wssecurity.timestamp.created", MessageContext.Scope.APPLICATION);
                context.put("wssecurity.timestamp.expires", expires);
                context.setScope("wssecurity.timestamp.expires", MessageContext.Scope.APPLICATION);

            } catch (SOAPFaultException e) {
                // Re-throw SOAPFaultException to propagate the fault
                throw e;
            } catch (Exception e) {
                // Catch any other unexpected exceptions and wrap them in a SOAPFaultException
                LOGGER.severe("Unexpected error processing WS-Security Timestamp: " + e.getMessage() + "\n" + getStackTrace(e));
                throw createSOAPFaultException("Internal server error during WS-Security Timestamp validation: " + e.getMessage(), SOAPConstants.SOAP_RECEIVER_FAULT);
            }
        }
        return true; // Continue processing the message
    }

    // Helper method to create SOAPFaultException
    private SOAPFaultException createSOAPFaultException(String reason, QName faultCode) {
        try {
            SOAPFault fault = SOAPFactory.newInstance().createFault(reason, faultCode);
            return new SOAPFaultException(fault);
        } catch (Exception e) {
            LOGGER.severe("Error creating SOAPFault: " + e.getMessage());
            // Fallback if fault creation itself fails
            return new SOAPFaultException(new QName(SOAPConstants.URI_NS_SOAP_1_1_ENVELOPE, "Server"), "Internal server error creating fault: " + e.getMessage());
        }
    }

    // Helper to get text content of a child element by name and namespace
    private String getChildElementText(SOAPElement parent, String namespaceURI, String localName) {
        NodeList children = parent.getElementsByTagNameNS(namespaceURI, localName);
        if (children.getLength() > 0) {
            return children.item(0).getTextContent();
        }
        return null;
    }

    // Helper to get stack trace as string
    private String getStackTrace(Throwable t) {
        java.io.StringWriter sw = new java.io.StringWriter();
        java.io.PrintWriter pw = new java.io.PrintWriter(sw);
        t.printStackTrace(pw);
        return sw.toString();
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        // Log the fault if needed. The fault is already generated and will be sent.
        LOGGER.info("TimestampSecurityHandler: handleFault encountered.");
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // Clean up any resources if necessary (not applicable for this simple handler)
    }
}

