package com.example.paymentgateway.publisher;

import com.example.paymentgateway.service.PaymentServiceImpl;

import javax.xml.ws.Endpoint;
import java.util.logging.Logger;

public class PaymentServicePublisher {

    private static final Logger LOGGER = Logger.getLogger(PaymentServicePublisher.class.getName());

    public static void main(String[] args) {
        String address = "http://localhost:8080/PaymentGateway/PaymentService";
        LOGGER.info("Publishing PaymentService at " + address);

        // Creates and publishes the SOAP service endpoint.
        Endpoint.publish(address, new PaymentServiceImpl());

        LOGGER.info("PaymentService published successfully. Access WSDL at " + address + "?wsdl");
        LOGGER.info("To stop the service, press Ctrl+C.");
    }
}